// Padrão Provider + Consumer
const MyContext = createContext();

function MyProvider({ children }) {
  const [value, setValue] = useState('default');
  return (
    <MyContext.Provider value={{ value, setValue }}>
      {children}
    </MyContext.Provider>
  );
}

function MyConsumer() {
  const { value } = useContext(MyContext);
  return <p>{value}</p>;
}

